#include "tall_skinny_matrix_multiplication_custom_tiling.h"
#include "register/op_def_registry.h"
#include <cmath>

namespace optiling {

static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN_ELEMS = 16;
static constexpr uint32_t OVERHEAD_BYTES = 8192;

static inline uint32_t AlignDown(uint32_t x, uint32_t a) {
    return (x / a) * a;
}

static inline uint32_t CeilDiv(uint32_t a, uint32_t b) {
    return (a + b - 1u) / b;
}

static ge::graphStatus TilingFunc(gert::TilingContext *context) {
    TallSkinnyMatrixMultiplicationCustomTilingData tiling;

    const gert::StorageShape *storageA = context->GetInputShape(0);
    const gert::StorageShape *storageB = context->GetInputShape(1);

    if (storageA->GetOriginShape().GetDimNum() != 2 || storageB->GetOriginShape().GetDimNum() != 2) {
        return ge::GRAPH_FAILED;
    }

    uint32_t M = static_cast<uint32_t>(storageA->GetOriginShape().GetDim(0));
    uint32_t K = static_cast<uint32_t>(storageA->GetOriginShape().GetDim(1));
    uint32_t N = static_cast<uint32_t>(storageB->GetOriginShape().GetDim(1));

    if (static_cast<uint32_t>(storageB->GetOriginShape().GetDim(0)) != K) {
        return ge::GRAPH_FAILED;
    }

    uint32_t bytesB = K * N * sizeof(float);
    uint32_t remaining = UB_BUDGET_BYTES - bytesB - OVERHEAD_BYTES;

    uint32_t tileM = 1;
    if (remaining > 0 && (K + N) > 0) {
        uint32_t bytesPerRowPair = 2 * (K + N) * sizeof(float);
        tileM = remaining / bytesPerRowPair;
        if (tileM > M) tileM = M;
        tileM = AlignDown(tileM, ALIGN_ELEMS);
        if (tileM < 1) tileM = 1;
    }

    uint32_t tileK = K;

    uint32_t numTilesM = CeilDiv(M, tileM);
    uint32_t blockDim = numTilesM;
    if (blockDim < 1) blockDim = 1;
    if (blockDim > 24) blockDim = 24;

    context->SetBlockDim(blockDim);

    tiling.set_M(M);
    tiling.set_K(K);
    tiling.set_N(N);
    tiling.set_tileM(tileM);
    tiling.set_tileK(tileK);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

